import anthropic
import json

client = anthropic.Anthropic()

# Simulated tool implementations
def fetch_product_details(feature: str) -> dict:
    catalogue = {
        "data-lineage": {
            "name": "Data Lineage Explorer",
            "summary": "Visualise end-to-end data flows, column-level impact analysis, and change history.",
            "key_benefits": ["Root-cause debugging in minutes", "Compliance audit trails", "Schema-change alerting"],
            "pricing_tier": "Enterprise",
        }
    }
    return catalogue.get(feature, {"error": "feature not found"})


def fetch_brand_guidelines() -> dict:
    return {
        "tone": "professional, direct, data-driven — never hyperbolic",
        "prohibited_claims": ["guaranteed ROI", "industry-leading"],
        "cta_style": "verb-first, one sentence max",
    }


tools = [
    {
        "name": "fetch_product_details",
        "description": "Return structured product information for a named feature.",
        "input_schema": {
            "type": "object",
            "properties": {"feature": {"type": "string"}},
            "required": ["feature"],
        },
    },
    {
        "name": "fetch_brand_guidelines",
        "description": "Return current brand voice and compliance rules.",
        "input_schema": {"type": "object", "properties": {}},
    },
]

SYSTEM = (
    "You are a B2B email copywriter. Before writing, always fetch product details "
    "and brand guidelines. Produce a two-email nurture sequence in JSON with keys "
    "email_1 and email_2, each containing subject and body."
)

messages = [
    {"role": "user", "content": "Write a nurture sequence for enterprise prospects interested in data-lineage."}
]

# Agentic loop
while True:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        system=SYSTEM,
        tools=tools,
        messages=messages,
    )

    if response.stop_reason == "end_turn":
        # Extract the final JSON text block
        for block in response.content:
            if hasattr(block, "text"):
                print(block.text)
        break

    # Process tool calls
    tool_results = []
    for block in response.content:
        if block.type == "tool_use":
            if block.name == "fetch_product_details":
                result = fetch_product_details(**block.input)
            elif block.name == "fetch_brand_guidelines":
                result = fetch_brand_guidelines()
            else:
                result = {"error": "unknown tool"}
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": json.dumps(result),
            })

    messages.append({"role": "assistant", "content": response.content})
    messages.append({"role": "user", "content": tool_results})
